export const Schema = z.object({
    世界: z.object({
        当前时间: z.string().describe('现代日本日期时间，格式如2018年6月20日 08:00'),
        当前地点: z.string().describe('精确到具体场所，如【东京都·东京都立咒术高专·一年级教室】'),
        近期事务: z.record(z.string().describe('事务名'), z.string().describe('事务描述')),
        主线阶段: z
            .string()
            .prefault('事件F3_五条悟担保与入学高专')
            .describe('当前剧情所处的主线阶段标识，参照世界书 world_timeline 中 -事件X: 条目，格式 事件X_简称'),
    }),
    玩家: z.object({
        等级: z.coerce
            .number()
            .transform(v => _.clamp(v, 1, 100))
            .prefault(1),
        经验值: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 9999))
            .prefault(0),
        身份: z.string().prefault('东京都立咒术高专一年级生'),
        咒术师等级: z
            .string()
            .prefault('四级')
            .describe('总监部认定的官方等级：四级<三级<二级<准一级<一级<特级，或 候补生/见习'),
        阵营: z.string().prefault('中立派').describe('改革派 / 保守派 / 中立派 / 诅咒师 / 羂索派 等'),
        御三家出身: z.string().prefault('无').describe('五条家 / 禅院家 / 加茂家 / 无(普通家系)'),
        通缉状态: z.string().prefault('无').describe('无 / 总监部通缉 / 死刑暂缓 等'),
        身体状况: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 100))
            .prefault(100),
        身体状态描述: z.string().prefault('健康'),
        咒力储备: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 9999))
            .prefault(20),
        咒力上限: z.coerce
            .number()
            .transform(v => _.clamp(v, 1, 9999))
            .prefault(20),
        永久损伤: z.string().prefault('无'),
        术式流派: z.string().prefault('未觉醒生得术式'),
        海外修行: z.string().prefault('无').describe('海外咒术体系修行经历：中国 / 欧洲 / 非洲 / 东南亚 / 无'),
        天与咒缚: z.string().prefault('无').describe('特殊体质：无 / 零咒力·极致肉体 / 巨量咒力·肉体脆弱 等'),
        生得术式: z.object({
            名称: z.string().prefault('未觉醒'),
            描述: z.string().prefault(''),
            掌握阶段: z.enum(['未觉醒', '已觉醒', '术式顺转', '术式反转', '领域展开']).prefault('未觉醒'),
            极之番: z.string().prefault('未掌握').describe('生得术式的究极奥义，使用后濒死/术式熔断；未掌握 或 招式名'),
        }),
        宿傩手指: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 20))
            .prefault(0)
            .describe('已吞下/收集的宿傩手指数（共20根，每根约5%力量）'),
        咒具: z.object({
            名称: z.string().prefault('无'),
            类型: z.string().prefault('无'),
            等级: z.string().prefault('普通').describe('咒具等级：普通 / 一级 / 特级'),
            耐久: z.coerce
                .number()
                .transform(v => _.clamp(v, 0, 100))
                .prefault(100),
            状态: z.string().prefault('极佳'),
        }),
        金钱: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 999999))
            .prefault(0),
        居住: z.string().prefault('【东京都·东京都立咒术高专·男生宿舍】'),
        当前任务: z.string().prefault('【无】'),
        当前位置: z.string().prefault('【东京都·杉泽第三高校·屋顶】'),
        当前服装: z.object({
            外套: z.string().prefault('高专制服外套'),
            内搭: z.string().prefault('白色T恤'),
            下装: z.string().prefault('黑色长裤'),
            足具: z.string().prefault('运动鞋'),
            战术功能: z.string().prefault('无').describe('服装的战术功能：防火面料 / 水下呼吸 / 咒力传导丝线 / 无'),
            备注: z.string().prefault(''),
        }),
        行囊: z
            .record(z.string().describe('物品名'), z.object({
            描述: z.string(),
            数量: z.coerce
                .number()
                .transform(v => _.clamp(v, 0, 9999))
                .prefault(1),
        }))
            .transform(data => _.pickBy(data, ({ 数量 }) => 数量 > 0)),
        能力: z.object({
            掌握战技: z.record(z.string().describe('战技名'), z.object({
                描述: z.string(),
                熟练度: z.enum(['入门', '熟练', '精通']).prefault('入门'),
            })),
            掌握术式: z.record(z.string().describe('术式名'), z.object({
                描述: z.string(),
                熟练度: z.enum(['入门', '熟练', '精通']).prefault('入门'),
            })),
            特殊能力: z.record(z.string().describe('能力名'), z.object({
                描述: z.string(),
                熟练度: z.enum(['入门', '熟练', '精通']).prefault('入门'),
            })),
            进阶技法: z.object({
                简易领域: z.boolean().prefault(false).describe('可中和敌方领域必中效果，现代掌握者不足十分之一'),
                领域展延: z.boolean().prefault(false).describe('中和敌方生得术式效果'),
                术式顺转最大输出: z.boolean().prefault(false).describe('咒力×3.5伤害×2.5，过热3层后熔断'),
                帐术: z.boolean().prefault(false).describe('认知遮蔽/物理封锁/通讯干扰等结界基础'),
                净灵术式: z.boolean().prefault(false).describe('诅咒净化/怨灵超度等辅助型术式'),
            }),
            咒力感知: z.string().prefault('被动约30米').describe('咒力感知范围，如 被动约30米 / 主动探测约200米'),
            束缚誓言: z.record(z.string().describe('誓言名'), z.object({
                内容: z.string().describe('限制内容'),
                代价或强化: z.string().describe('换取的强化或承担的代价'),
            })),
            式神: z.record(z.string().describe('式神名，如玉犬/鵺/大蛇/満象/魔虚罗'), z.object({
                描述: z.string(),
                状态: z.enum(['可召唤', '调伏中', '已破坏']).prefault('可召唤'),
            })),
        }),
        战斗状态: z.object({
            是否战斗中: z.boolean().prefault(false),
            当前敌人: z.string().prefault('无'),
            基础战斗力: z.coerce
                .number()
                .transform(v => _.clamp(v, 0, 9999))
                .prefault(10),
            有效战斗力: z.coerce
                .number()
                .transform(v => _.clamp(v, 0, 9999))
                .prefault(10),
            术式熔断: z.boolean().prefault(false).describe('生得术式回路烧毁，无法使用生得术式直至恢复'),
            状态效果: z.record(z.string().describe('状态名'), z.string().describe('状态描述')).prefault({}),
        }),
        死灭回游: z.object({
            参与中: z.boolean().prefault(false),
            泳者点数: z.coerce
                .number()
                .transform(v => _.clamp(v, 0, 9999))
                .prefault(0),
            所在结界: z.string().prefault('无').describe('东京/仙台/大阪/京都…等十大结界之一，或 无'),
        }),
    }),
    角色好感度: z.record(z.string().describe('角色名'), z.object({
        已登场: z.boolean().prefault(false).describe('是否已在剧情中登场并被玩家认识；true 时状态栏羁绊列表才显示'),
        好感: z.coerce
            .number()
            .transform(v => _.clamp(v, -100, 100))
            .prefault(0),
        信任: z.coerce
            .number()
            .transform(v => _.clamp(v, -100, 100))
            .prefault(0),
        关系: z.string().prefault('陌生'),
        本回合变动: z.string().prefault(''),
    })),
    战斗记录: z.object({
        累计祓除咒灵: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 9999))
            .prefault(0),
        累计完成任务: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 9999))
            .prefault(0),
        累计修炼天数: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 9999))
            .prefault(0),
        黑闪次数: z.coerce
            .number()
            .transform(v => _.clamp(v, 0, 9999))
            .prefault(0)
            .describe('成功打出黑闪的累计次数'),
        领域展开觉醒: z.boolean().prefault(false),
        黑闪领悟: z.boolean().prefault(false),
        反转术式觉醒: z.boolean().prefault(false),
    }),
    系统日志: z
        .record(z.string().describe('日志条目名'), z.string().describe('日志内容'))
        .transform(data => _(data).entries().takeRight(20).fromPairs().value()),
});
